gangara opara kabhu yayena kuliya',NULL,NULL),('cb.antya.5.710','cb','cb.antya.5','ЧБ Антья 5.710',710,NULL,'visese sukrti ati badagachi-grama nityananda-svarupera viharera sthana',NULL,NULL),('cb.antya.5.711','cb','cb.antya.5','ЧБ Антья 5.711',711,NULL,'badagachi-gramera yateka bhagyodaya tahara karite nai pari samuccaya',NULL,NULL),('cb.antya.5.712','cb','cb.antya.5','ЧБ Антья 5.712',712,NULL,'nityananda-svarupera parisada-gana
niravadhi sabei paramananda-mana',NULL,NULL),('cb.antya.5.713','cb','cb.antya.5','ЧБ Антья 5.713',713,NULL,'karo kona karma nai sankirtana-vine sabara gopala-bhava bade ksane ksane',NULL,NULL),('cb.antya.5.714','cb','cb.antya.5','ЧБ Антья 5.714',714,NULL,'vetra vamsi singa chanda-dadi gunja-hara
tada khadu hate, paye nupura sabara',NULL,NULL),('cb.antya.5.715','cb','cb.antya.5','ЧБ Антья 5.715',715,NULL,'niravadhi sabara sarire krsna-bhava asru-kampa-pulaka—yateka anuraga',NULL,NULL),('cb.antya.5.716','cb','cb.antya.5','ЧБ Антья 5.716',716,NULL,'sabara saundarya yena abhinna madana niravadhi sabei karena sankirtana',NULL,NULL),('cb.antya.5.717','cb','cb.antya.5','ЧБ Антья 5.717',717,NULL,'paiya abhaya svami prabhu nityananda niravadhi kautuke thakena bhakta-vrnda',NULL,NULL),('cb.antya.5.718','cb','cb.antya.5','ЧБ Антья 5.718',718,NULL,'nityananda-svarupera dasera mahima sata vatsare о karibare nahi sima',NULL,NULL),('cb.antya.5.719','cb','cb.antya.5','ЧБ Антья 5.719',719,NULL,'tathapiha nama kahi—jani yanra yanra nama matra smarane о tariye samsara',NULL,NULL),('cb.antya.5.720','cb','cb.antya.5','ЧБ Антья 5.720',720,NULL,'yanra yanra sange nityanandera vihara
sabe nanda-gosthi gopa-gopi-avatara',NULL,NULL),('cb.antya.5.721','cb','cb.antya.5','ЧБ Антья 5.721',721,NULL,'nityananda-svarupera nisedha lagiya
purva-nama na likhila vidita kariya',NULL,NULL),('cb.antya.5.722','cb','cb.antya.5','ЧБ Антья 5.722',722,NULL,'parama parsada—ramadasa mahasaya
niravadhi isvara-bhave se katha kaya',NULL,NULL),('cb.antya.5.723','cb','cb.antya.5','ЧБ Антья 5.723',723,NULL,'yanra vakya keha jhata na pare bujhite
niravadhi nityananda yanra hrdayete',NULL,NULL);
INSERT OR REPLACE INTO verse_texts (id,verse_id,edition_id,translation,purport) VALUES ('cb.antya.5.601.ru','cb.antya.5.601','cb-ru','Грешные бандиты вскоре придумали новый план и собрались поблизости от дома, где остановился Нитьянанда-чандра.',NULL),('cb.antya.5.602.ru','cb.antya.5.602','cb-ru','По воле провидения, та ночь выдалась совершенно непроглядной и тёмной из-за обилия облаков. Кроме разбойников, никто и никуда той ночью не выходил.',NULL),('cb.antya.5.603.ru','cb.antya.5.603','cb-ru','В ту жуткую ночь, каждый из бандитов взял с собой от пяти до десяти единиц оружия.
Слово качана означает "принёс".',NULL),('cb.antya.5.604.ru','cb.antya.5.604','cb-ru','Как только они прокрались во двор дома, темнота сгустилась до такой степени, что они уже ничего не видели.',NULL),('cb.antya.5.605.ru','cb.antya.5.605','cb-ru','Бандиты буквально ослепли от темноты и их жизненные потоки воздуха, их мысли и умы сковал ужас.',NULL),('cb.antya.5.606.ru','cb.antya.5.606','cb-ru','Некоторые упали в ров, где их искусали пиявки, насекомые и пчелы.
Фраза гада-кхайра означает ров, который окружает дворец или резиденцию царя или домовладельца.',NULL),('cb.antya.5.607.ru','cb.antya.5.607','cb-ru','Кто-то свалился в яму, в которую сбрасывали остатки пищи, и пострадал от укусов скорпионов и прочих насекомых.',NULL),('cb.antya.5.608.ru','cb.antya.5.608','cb-ru','Другие упали в колючие кусты, где острые шипы так впились в их тела, что они не могли даже шелохнуться.',NULL),('cb.antya.5.609.ru','cb.antya.5.609','cb-ru','Некоторые упали в канаву, поломали себе руки и ноги, и жалобно плакали.',NULL),('cb.antya.5.610.ru','cb.antya.5.610','cb-ru','Кого-то из разбойников поразила лихорадка. Все как один были перепуганы не на шутку.',NULL),('cb.antya.5.611.ru','cb.antya.5.611','cb-ru','Ко всем бедам, озорной Индра послал туда ураган и ливень.',NULL),('cb.antya.5.612.ru','cb.antya.5.612','cb-ru','Сначала бандиты претерпели боль от укусов пиявок и насекомых, а затем их страдания усилились ураганом и ливнем.',NULL),('cb.antya.5.613.ru','cb.antya.5.613','cb-ru','На них обрушился град, но не убил их, а просто заставил окунуться в океан страданий.',NULL),('cb.antya.5.614.ru','cb.antya.5.614','cb-ru','Когда прямо туда ударила молния, от ужаса они совершенно забылись и потеряли сознание.
Слово маха-джханджхана означает "молния".',NULL),('cb.antya.5.615.ru','cb.antya.5.615','cb-ru','Из-за сильного ливня бандиты промокли до нитки и дрожали от пронизывающего холода.',NULL),('cb.antya.5.616.ru','cb.antya.5.616','cb-ru','Они были ослеплены и ничего не видели, а сильный дождь и холод ещё больше усилили их страдания.',NULL),('cb.antya.5.617.ru','cb.antya.5.617','cb-ru','Зная, что они пришли навредить Нитьянанде, гневный Индра присудил им суровое наказание.',NULL),('cb.antya.5.618.ru','cb.antya.5.618','cb-ru','Через некоторое время брахмана-главаря бандитов, вдруг озарила мысль, что им ещё очень сильно повезло.',NULL),('cb.antya.5.619.ru','cb.antya.5.619','cb-ru','Брахман подумал, "Нитьянанда – это не человеческое существо. Несомненно, Он Верховный Господь. Не может Он быть обычным человеком.',NULL),('cb.antya.5.620.ru','cb.antya.5.620','cb-ru','"Однажды Он сбил нас с толку сном, но мы не поняли этого, из-за влияния иллюзорной энергии Господа".',NULL),('cb.antya.5.621.ru','cb.antya.5.621','cb-ru','"На другой день Он явил нам этих удивительных воинов, но мы не вняли голосу рассудка".
622
"Такие грешники как мы заслужили все эти страдания, потому что пытались украсть драгоценности у Самого Господа".',NULL),('cb.antya.5.623.ru','cb.antya.5.623','cb-ru','"Кто же сможет защитить меня от величайшей опасности? Нет у меня другого прибежища, кроме Нитьянанды".',NULL),('cb.antya.5.624.ru','cb.antya.5.624','cb-ru','Размышляя таким образом, брахман всё взвесил, и решил искать прибежище у лотосных стоп Нитьянанды.',NULL),('cb.antya.5.625.ru','cb.antya.5.625','cb-ru','Размышляя о Его лотосных стопах, даже тот кто совершил миллионы преступлений, тут же избавится от всех затруднений.',NULL),('cb.antya.5.626.ru','cb.antya.5.626','cb-ru','О Нитьянанда, о Шри Бала-гопала, смилуйся и защити меня! О Господь, Ты поддерживаешь всех живых существ, будь милостив, дай мне убежище!"',NULL),('cb.antya.5.627.ru','cb.antya.5.627','cb-ru','"О Господь, если человек спотыкается и всем весом ударяется о землю, земля поддерживает его".
Когда человек падает на землю, земля не даёт ему провалиться дальше, и любезно даёт ему опору.
Есть такая поговорка:
"У того, кто споткнулся и упал есть только одна поддержка – земля, позволяющая снова подняться. Точно так же, о Господь, тот кто совершил преступление по отношению к Тебе, не найдёт защиту ни у кого, кроме Тебя".',NULL),('cb.antya.5.628.ru','cb.antya.5.628','cb-ru','"Точно так же, страдания того кто оскорблял Твои лотосные стопы, смягчаются простым памятованием о Тебе".
Если человек претерпевает страдания или нищету, гневается или испытывает разочарование Верховным Господом, то его гнев или разочарование становятся причиной оскорбления. Столкнувшийся с какими-то бедствиями или нуждой, человек должен понимать, что его единственный защитник – Господь.',NULL),('cb.antya.5.629.ru','cb.antya.5.629','cb-ru','"Ты прощаешь живым существам все их грехи, и Ты даруешь милость их падшим душам".',NULL),('cb.antya.5.630.ru','cb.antya.5.630','cb-ru','"Я убивал брахманов и коров. О Господь, не найти преступника более грешного, чем я".',NULL),('cb.antya.5.631.ru','cb.antya.5.631','cb-ru','"Если самый отъявленный грешник найдёт у Тебя прибежище, он освободится от всех материальных оков".',NULL),('cb.antya.5.632.ru','cb.antya.5.632','cb-ru','"О Господь, Ты защищаешь живых существ со времени их рождения и вплоть до момента их смерти".',NULL),('cb.antya.5.633.ru','cb.antya.5.633','cb-ru','"О Господь, пожалуйста, защити меня от этих бед. Если я останусь в живых, я навсегда запомню Твой урок".',NULL),('cb.antya.5.634.ru','cb.antya.5.634','cb-ru','"Рождение за рождением – Ты мой Господь, а я Твой слуга. Буду я жить или умру, у меня нет других желаний, кроме этого".',NULL),('cb.antya.5.635.ru','cb.antya.5.635','cb-ru','Когда самый милосердный Нитьянанда-чандра услышал эти молитвы, Он освободил этих бандитов.',NULL),('cb.antya.5.636.ru','cb.antya.5.636','cb-ru','Благодаря такому умонастроению бандитов, зрение вернулось к ним.',NULL),('cb.antya.5.637.ru','cb.antya.5.637','cb-ru','Благодаря тому, что они предались Нитьянанде Сварупе, они избавились от страданий, вызванных ураганом.',NULL),('cb.antya.5.638.ru','cb.antya.5.638','cb-ru','Вскоре после этого бандиты нашли дорогу и едва живые вернулись домой.',NULL),('cb.antya.5.639.ru','cb.antya.5.639','cb-ru','После возвращения домой, бандиты сразу же отправились принимать омовение в
Ганге.',NULL),('cb.antya.5.640.ru','cb.antya.5.640','cb-ru','Позже, брахман-главарь бандитов, рыдая предстал перед лотосными стопами Нитьянанды.',NULL),('cb.antya.5.641.ru','cb.antya.5.641','cb-ru','Нитьянанда, Господь вселенной, сидя окидывал Своим милостивым взглядом падшие души.',NULL),('cb.antya.5.642.ru','cb.antya.5.642','cb-ru','Со всех сторон преданные пели имя Хари, а драгоценный камень среди авадхут ревел от восторга.',NULL),('cb.antya.5.643.ru','cb.antya.5.643','cb-ru','В это время там и появился страшный разбойник-брахман, и подняв руки, воскликнул: "Будь милостив, защити меня!", и предложил свои поклоны.',NULL),('cb.antya.5.644.ru','cb.antya.5.644','cb-ru','Стоя со вздыбленными волосами, он непрестанно проливал слёзы и дрожал всем телом.',NULL),('cb.antya.5.645.ru','cb.antya.5.645','cb-ru','Он постоянно ревел и вопил в экстазе любви, пока рыдая совершенно не отключился от внешнего восприятия.',NULL),('cb.antya.5.646.ru','cb.antya.5.646','cb-ru','Узрев достояния Нитьянанды Сварупы, он от счастья пустился в пляс.',NULL),('cb.antya.5.647.ru','cb.antya.5.647','cb-ru','Он поднял руки и постоянно взывал: "О Нитьянанда, освободитель падших душ, спаси меня!"',NULL),('cb.antya.5.648.ru','cb.antya.5.648','cb-ru','Когда люди увидели поведение бандита, то просто обмерли от изумления и подумали, "Как может такой разбойник вести себя подобным образом?"',NULL),('cb.antya.5.649.ru','cb.antya.5.649','cb-ru','Кто-то сказал, "Похоже, что он задумал какую-то хитрость. Под этим предлогом он может позже ограбить чей-то дом".
По своей природе двуличные люди внешне проявляют простоту и смирение, но при первой же возможности совершают беззаконие.',NULL),('cb.antya.5.650.ru','cb.antya.5.650','cb-ru','Кто-то сказал: "Нитьянанда освободитель падших душ. По Его милости сердце разбойника преобразилось".',NULL),('cb.antya.5.651.ru','cb.antya.5.651','cb-ru','Увидев симптомы экстатической любви, проявленные в теле брахмана, Нитьянанда улыбнулся и спросил.',NULL),('cb.antya.5.652.ru','cb.antya.5.652','cb-ru','Господь сказал, "Ответь Мне, о брахман, как объяснить твоё поведение? Я нахожу его просто удивительным".',NULL),('cb.antya.5.653.ru','cb.antya.5.653','cb-ru','"Ты видишь или слышишь нечто, что открыло тебе сознание Кришны? Не волнуйся, расскажи всё откровенно".',NULL),('cb.antya.5.654.ru','cb.antya.5.654','cb-ru','Услышав слова Господа, удачливый брахман лишился дара речи, и продолжал рыдать.',NULL),('cb.antya.5.655.ru','cb.antya.5.655','cb-ru','Он упал на землю и катался по всему двору. Он непроизвольно смеялся, плакал, танцевал и пел.',NULL),('cb.antya.5.656.ru','cb.antya.5.656','cb-ru','Через некоторое время брахман успокоился и обратился к Господу.',NULL),('cb.antya.5.657.ru','cb.antya.5.657','cb-ru','"О Господь, я живу в Надие. Хотя люди считали меня брахманом, я вёл себя подобно охотнику или собакоеду".',NULL),('cb.antya.5.658.ru','cb.antya.5.658','cb-ru','"Я постоянно занимался грабежами вместе с такими же нечестивцами. С самого своего рождения кроме насилия над другими, я не сделал ничего хорошего".',NULL),('cb.antya.5.659.ru','cb.antya.5.659','cb-ru','"Жителей Навадвипы бросало в дрожь от одного моего вида. Наверное трудно будет найти грех, который бы я не совершил".',NULL),('cb.antya.5.660.ru','cb.antya.5.660','cb-ru','"Когда я увидел Твои драгоценные украшения, то решил их украсть".',NULL),('cb.antya.5.661.ru','cb.antya.5.661','cb-ru','"Однажды я привёл группу вооружённых бандитов, чтобы похитить украшения с Твоего божественного тела".',NULL),('cb.antya.5.662.ru','cb.antya.5.662','cb-ru','"В ту ночь, о Господь, Ты сбил нас с толку сном, но из-за влияния Твоей иллюзорной энергии, тогда я ничего не понял".',NULL),('cb.antya.5.663.ru','cb.antya.5.663','cb-ru','"На следующуя ночь, мы сделали различные подношения и вознесли молитвы Чанди. Потом мы пришли к Твоему дому, вооружённые мечами, ножами и трезубцами".',NULL),('cb.antya.5.664.ru','cb.antya.5.664','cb-ru','"В ту ночь мы увидели нечто поразительное. Весь дом был окружён воинами".',NULL),('cb.antya.5.665.ru','cb.antya.5.665','cb-ru','"Каждый из тех воинов обладал силой бешенного слона. Все они были украшены гирляндами, достигающими их колен".',NULL),('cb.antya.5.666.ru','cb.antya.5.666','cb-ru','"Все они неустанно повторяли имя Хари, пока Ты блаженно отдыхал в доме".',NULL),('cb.antya.5.667.ru','cb.antya.5.667','cb-ru','"И всё же, наши сердца были так осквернены, что мы не смогли понять Твоей славы".',NULL),('cb.antya.5.668.ru','cb.antya.5.668','cb-ru','"Мы думали, что эти воины пришли из другого города. Так решив, мы в ту ночь вернулись домой".',NULL),('cb.antya.5.669.ru','cb.antya.5.669','cb-ru','"Спустя нескольких дней, прошлой ночью, мы снова вернулись. Но как только мы приблизились к дому, мы лишились способности видеть".',NULL),('cb.antya.5.670.ru','cb.antya.5.670','cb-ru','"Оказавшись вместе с подельниками во дворе дома, мы лишились зрения и начали спотыкаться и падать".',NULL),('cb.antya.5.671.ru','cb.antya.5.671','cb-ru','"Мы страдали от уколов шипов, укусов пиявок и насекомых, дождя и града. Мы были так измучены, что у нас не было сил вернуться домой".',NULL),('cb.antya.5.672.ru','cb.antya.5.672','cb-ru','"Когда мы претерпели эти наказания Ямараджи, в конечном счёте, у нас пробудилась преданность Тебе".',NULL),('cb.antya.5.673.ru','cb.antya.5.673','cb-ru','"По Твоей милости мы вспомнили о Тебе и полностью сосредоточили свои мысли на Твоих лотосных стопах".',NULL),('cb.antya.5.674.ru','cb.antya.5.674','cb-ru','"Тогда и восстановилось наше истинное видение. Таково Твоё могущество, о освободитель падших!"',NULL),('cb.antya.5.675.ru','cb.antya.5.675','cb-ru','"Причиной того, что все мы избавились от тех страданий, стало памятование о Тебе".',NULL),('cb.antya.5.676.ru','cb.antya.5.676','cb-ru','"Памятуя о Тебе, человек освобождается от всех оков невежества и легко достигает Твоей обители – Вайкунтхи".',NULL),('cb.antya.5.677.ru','cb.antya.5.677','cb-ru','Произнеся эти слова, брахман громко разрыдался. Таковы игры Авадхуты Нитьянанды.',NULL),('cb.antya.5.678.ru','cb.antya.5.678','cb-ru','Когда все услышали о случившемся, то просто застыли от изумления. Затем все предложили брахману свои поклоны.',NULL),('cb.antya.5.679.ru','cb.antya.5.679','cb-ru','Брахман сказал: "О Господь, а сейчас позволь мне уйти. Я не имею права оставаться в этом теле".',NULL),('cb.antya.5.680.ru','cb.antya.5.680','cb-ru','"Поскольку я намеревался причинить Тебе вред, искупить это я могу только тем, что утоплюсь в Ганге".',NULL),('cb.antya.5.681.ru','cb.antya.5.681','cb-ru','Искренние слова брахмана очень порадовали Господа и преданных.',NULL),('cb.antya.5.682.ru','cb.antya.5.682','cb-ru','Господь сказал: "О брахман, ты очень удачлив. Ты несомненно, рождение за рождением был и остаёшься слугой Кришны".',NULL),('cb.antya.5.683.ru','cb.antya.5.683','cb-ru','"Иначе как объяснить, что Он дарует тебе такую милость? Кто кроме Его слуги способен видеть Его богатства?"',NULL),('cb.antya.5.684.ru','cb.antya.5.684','cb-ru','"Чайтанья Госани явился, чтобы освобождать падшие души. В этом не может быть никаких сомнений".',NULL),('cb.antya.5.685.ru','cb.antya.5.685','cb-ru','"Послушай, о брахман, Я избавлю тебя от всех последствий твоих преступлений, если ты впредь не будешь грешить".
Если грешник раскается в совершённых грехах перед истинным духовным учителем, то он освободится от всех реакций, при условии, что не вернётся к преступной деятельности. Если человек принимает наказание, как искупление, он делает выводы на будущее. Однако, в некоторых случаях, наказанный вновь совершает грехи, за которые уже был наказан. Когда человек избавляется от склонности к совершению грехов, он освобождается от всех последствий преступлений, совершённых в прошлом. Если это желание искреннее, то человек не сможет вернуться к прежним греховным наклонностям. Если же человек освободился не полностью, то семя греха, естественно, вновь вынудит его вернуться на путь греха. Как банкроту, который не может погасить задолженности, даётся новая возможность погасить долги по решению суда, так и уму, склонному к благочестивой жизни и отказавшемуся от желания впредь совершать греховные действия, и вредить другим, даётся новый шанс. Шри Нитьянанда Прабху освободил грешного брахмана от последствий его прошлых грехов и дал ему новую жизнь.',NULL),('cb.antya.5.686.ru','cb.antya.5.686','cb-ru','"Откажись от насилия над другими, грабежей и прочих греховных деяний, и никогда не повторяй своих ошибок".',NULL),('cb.antya.5.687.ru','cb.antya.5.687','cb-ru','"Прими духовный образ жизни и повторяя имя Хари, и так ты сможешь спасти себя и других".',NULL),('cb.antya.5.688.ru','cb.antya.5.688','cb-ru','"Ты должен обратиться ко всем негодяям и бандитам, и склонить их к религиозной жизни".',NULL),('cb.antya.5.689.ru','cb.antya.5.689','cb-ru','После того как Нитьянанда произнёс эти слова, Он снял со Своей шеи гирлянду и с радостью вручил её брахману.',NULL),('cb.antya.5.690.ru','cb.antya.5.690','cb-ru','Затем, все дружно воскликнули, "Джая! Джая!" Таким образом, брахман был освобождён от всех материальных привязанностей.',NULL),('cb.antya.5.691.ru','cb.antya.5.691','cb-ru','Брахман с огромным смирением, заливаясь слезами, прижался к лотосным стопам Господа.',NULL),('cb.antya.5.692.ru','cb.antya.5.692','cb-ru','"О Нитьянанда, о освободитель падших душ, смилуйся и дай этому грешному человеку прибежище у Своих лотосных стоп!"',NULL),('cb.antya.5.693.ru','cb.antya.5.693','cb-ru','"Ведь я желал причинить Тебе вред. Какая печальная судьба ожидает такого грешника, как я?"',NULL),('cb.antya.5.694.ru','cb.antya.5.694','cb-ru','Нитьянанда Прабху, океан милости, после этих слов поместил Свою лотосную стопу на голову брахмана.',NULL),('cb.antya.5.695.ru','cb.antya.5.695','cb-ru','Когда лотосная стопа Господа опустилась на его голову, все последствия преступлений, совершённых брахманом, просто исчезли.',NULL),('cb.antya.5.696.ru','cb.antya.5.696','cb-ru','Благодаря влиянию этого брахмана, вся разбойники нашли прибежище у Господа Чайтаньи и встали на путь религиозности.',NULL),('cb.antya.5.697.ru','cb.antya.5.697','cb-ru','Они отказались от грабежей, насилия по отношению к другим, и прочей беспутной деятельности и уподобились великим святым.',NULL),('cb.antya.5.698.ru','cb.antya.5.698','cb-ru','Все они читали имя Хари сотни тысяч раз, и стали очень сведущими в преданном служении Господу Вишну.
Необходимо видеть различие между преданностью Вишну и преданностью объектам, отличным от Вишну. В преданном служении Вишну нет и тени удовлетворения собственных чувств, а в поклонении другим, отличным от Вишну полубогам – присутствует стремление удовлетворить свои эгоистические мотивы. Тем не менее, в преданном служении Вишну различают три категории – кшина (слабый), мадхйам (средний), и нипуна (сведущий). Воспеванием имени Хари человек пробуждает свою любовь к Кришне и обретает достаточную квалификацию, чтобы наслаждаться самой возвышенной из трансцендентных рас.',NULL),('cb.antya.5.699.ru','cb.antya.5.699','cb-ru','Они упивалась любовью к Кришне и постоянно пели имена Хари, благодаря океану милости – Шри Нитьянанде Прабху.',NULL),('cb.antya.5.700.ru','cb.antya.5.700','cb-ru','Прибежище у Верховного Господа не так просто обрести посредством других Его воплощений, но Нитьянанда постоянно побуждал каждого предаться Господу Чайтанье.',NULL),('cb.antya.5.701.ru','cb.antya.5.701','cb-ru','На любого брахмана, который не принимает Нитьянанду Сварупу, следует смотреть как на вора и негодяя.
Если даже возвышенный в мирском понимании брахман, наделённый смирением и знаниями не признаёт Шри Нитьянанду Сварупу, то такой глупец пополняет ряды воров и негодяев, уподобляясь им, или к категории жуликов и воров, к которым их относит Шри Нитьянанда.
Стих 702-703
Преобразования экстатической любви, которых желают лучшие из йогов, как слёзы, дрожь, вздыбленные волосы и рёв, были обретены даже негодяями и грабителями. Вот каким могуществом обладает Нитьянанда Сварупа.
Слово дакаита (хинди) означает "негодяй" или "грабитель".',NULL),('cb.antya.5.704.ru','cb.antya.5.704','cb-ru','О братья, просто поклоняйтесь Нитьянанде, по милости которого человек может освободиться и обрести Господа Гаурачандру.',NULL),('cb.antya.5.705.ru','cb.antya.5.705','cb-ru','Тот, кто слушает повествования о Нитьянанде, достигнет лотосных стоп Господа Гаурачандры.',NULL),('cb.antya.5.706.ru','cb.antya.5.706','cb-ru','Любой, кто слушает эти повествования о освобождении разбойников, узрит Нитьянанду Прабху и Господа Чайтанью.',NULL),('cb.antya.5.707.ru','cb.antya.5.707','cb-ru','Так бесстрашно и радостно Нитьянанда наслаждался Своими играми.',NULL),('cb.antya.5.708.ru','cb.antya.5.708','cb-ru','После этого Нитьянанда в сопровождении Своих спутников отправился в путь и посещал деревню за деревней, счастливо проводя киртаны.',NULL),('cb.antya.5.709.ru','cb.antya.5.709','cb-ru','Он посещал Кханачауду, Бадагачи и Догачию, а иногда заходил и в Кулию, которая находится на другом берегу Ганги.
Другой вариант прочтения для Кханачауда является Кхалачада.
Некоторые люди называют это село (Кханачауда) Кханаджода, Кханачаута или Кханачауда. Кхалачада означает русло реки или старое высохшее русло или ров, где ранее протекала Ганга. Деревня Бадагачи существует и по сей день, и находится неподалёку от деревень Калашира-кхала и Рукунапура. В этой деревне находится дом отца Шри Нитьянанды.
Деревня Догачия находится недалеко от Кришнанагары.Там жил один из преданных Нитьянанды.
Шри Навадвипа это часть Шри Маяпура, которая находится на восточном берегу Ганги. Коладвипа или Кулия, расположена на западном берегу. По мнению всех учёных людей, нынешний город Навадвипа во времена Махапрабху, был известен как Кулия. Шри Маяпур-Навадвипа расположена на восточном берегу, напротив деревни Кулия. По утверждению, приведённому в Шри Чайтанья-бхагавате: сабе матра ганга надийая кулийая – "Только Ганга отделяет Надию от Кулии", Шри-Навадвипа-Маяпура всегда находилась на восточном берегу Ганги, а Кулия всегда была на западном берегу. Даже сейчас такие места как Кулияра-ганджа, Амада-кола, Тегхарира-кола и Кулияра-даха, указывают на местоположение древней Кулии.',NULL),('cb.antya.5.710.ru','cb.antya.5.710','cb-ru','Деревня Бадагачи особенно славна тем, что Нитьянанда Сварупа провёл там множество игр.',NULL),('cb.antya.5.711.ru','cb.antya.5.711','cb-ru','Трудно оценить счастливую судьбу села Бадагачи.
Слово самуччайа означает "понять", "рассчитать", или "оценить".',NULL),('cb.antya.5.712.ru','cb.antya.5.712','cb-ru','Все спутники Нитьянанды Сварупы постоянно были переполнены огромным восторгом.',NULL),('cb.antya.5.713.ru','cb.antya.5.713','cb-ru','Они были заняты исключительно санкиртаной, и все были полностью поглощены настроением пастушков.',NULL),('cb.antya.5.714.ru','cb.antya.5.714','cb-ru','Они носили пруты, флейты, рожки, веревки и ожерелья из гунджа. Их запястья и лодыжки были украшены браслетами и колокольчиками.',NULL),('cb.antya.5.715.ru','cb.antya.5.715','cb-ru','Их тела были всегда наполнены экстазом сознания Кришны, и они проявляли симптомы чистого преданного служения, как плач, дрожь и вздыбленные волосы.',NULL),('cb.antya.5.716.ru','cb.antya.5.716','cb-ru','Их красота была сравнима с обаянием бога любви, и они всегда были заняты санкиртаной.',NULL),('cb.antya.5.717.ru','cb.antya.5.717','cb-ru','Обретя своего бесстрашного властелина – Нитьянанду Прабху, преданные всегда были счастливы.',NULL),('cb.antya.5.718.ru','cb.antya.5.718','cb-ru','Даже за сто лет я бы не смог описать всё величие преданных Нитьянанды Сварупы.',NULL),('cb.antya.5.719.ru','cb.antya.5.719','cb-ru','И всё же, я напомню имена тех, кого я знаю, чтобы люди просто вспоминая их имена, освобождались от материального сознания.',NULL),('cb.antya.5.720.ru','cb.antya.5.720','cb-ru','Все преданные, с которыми Нитьянанда проводил игры, были воплощениями пастушков и девушек-пастушек – детей из общины Нанды Махараджи.
Спутниками Шри Нитьянанды были мальчики-пастушки, девушки-пастушки и члены семьи Нанды Махараджи в играх Кришны.',NULL),('cb.antya.5.721.ru','cb.antya.5.721','cb-ru','Я не буду упоминать их прошлые имена из-за запрета Нитьянанды Сварупы.
Со слов самих преданных, Нитьянанда запрещал им прилюдно использовать имена, под которыми Его спутники и преданные были известны во времена игр Кришны. Но вся история имён преданных со времён игр Кришны, и имён спутников Шри Нитьянанды, под которыми они принимали участие в играх Гауры, описана Шри Кави-Карнапуром в книге Шри Гаура-ганоддеша-дипика.',NULL),('cb.antya.5.722.ru','cb.antya.5.722','cb-ru','Его основным спутником был Рамадаса Махашая, который всегда говорил, пребывая в настроении Верховного Господа.',NULL),('cb.antya.5.723.ru','cb.antya.5.723','cb-ru','Никто не мог сразу понять его слов, а Нитьянанда всегда пребывал в его сердце.',NULL);